  "title": "Stability Score Disbursement Integration Extension",
  "description": "Extension for conditional disbursement based on Stability Score.",
  "type": "object",
  "properties": {
    "applicantId": {
      "type": "string",
      "format": "uuid",
      "description": "Reference to applicant from base schema."
    },
    "disbursementDetails": {
      "type": "object",
      "description": "Details for benefits disbursement, including restrictions.",
      "properties": {
        "eligibleAmount": {
          "type": "number",
          "description": "Total eligible cash assistance amount (USD).",
          "minimum": 0
        },
        "stabilityScoreThreshold": {
          "type": "number",
          "description": "Configurable threshold (default: 50).",
          "minimum": 0,
          "maximum": 100,
          "default": 50
        },
        "conversionPercentage": {
          "type": "number",
          "description": "Percentage of amount converted to credits if below threshold (default: 50%).",
          "minimum": 0,
          "maximum": 100,
          "default": 50
        },
        "restrictedCredits": {
          "type": "object",
